package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setup() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParseReturnsCSVParser() throws Exception {
        Reader reader = mock(Reader.class);

        // Mock CSVParser instance
        CSVParser mockParser = mock(CSVParser.class);

        // Spy on CSVFormat instance
        CSVFormat spyFormat = spy(csvFormat);

        // Use reflection to mock the constructor call inside parse()
        // Because parse() calls: new CSVParser(reader, this)
        // We cannot directly mock new, so we mock CSVParser constructor via Mockito's inline mock maker
        // But since it's not possible here, instead we mock parse() method itself

        // Mock parse(Reader) method on spy to return mockParser
        doReturn(mockParser).when(spyFormat).parse(reader);

        CSVParser parser = spyFormat.parse(reader);

        assertNotNull(parser);
        assertEquals(mockParser, parser);
    }

    @Test
    void testParseWithNullReaderThrowsNPE() {
        assertThrows(NullPointerException.class, () -> csvFormat.parse(null));
    }

    @Test
    void testParseCreatesCSVParserWithThisInstance() throws Exception {
        Reader reader = mock(Reader.class);

        CSVParser parser = new CSVParser(reader, csvFormat);
        assertNotNull(parser);
    }
}
